queries.sparql:
PREFIX : <http://ambrosia.example.org/healthcare#>
PREFIX p: <http://ambrosia.example.org/healthcare/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasSpecialty ?child ; p:hasMedical_Center ?parent . } GROUP BY ?child }
  ?child p:Type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Medical_Center } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/healthcare#>
PREFIX p: <http://ambrosia.example.org/healthcare/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasSpecialty ?child ; p:hasMedical_Center ?parent . } GROUP BY ?child }
  ?child p:Type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Medical_Center } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?type WHERE {
  ?medical_center_specialty a :Medical_Center_Specialty .
  ?specialty a :Specialty .
  ?medical_center_specialty p:hasSpecialty ?specialty .
  ?medical_center a :Medical_Center .
  ?medical_center_specialty p:hasMedical_Center ?medical_center .
  ?medical_center p:name ?name .
  ?specialty p:Type ?type .
} }
}
